svg.script:
var currentInput = '0';
var previousInput = '';
var operator = null;
var shouldResetScreen = false;
var memory = 0;
var grandTotal = 0;
var dataSet = [];

var doc = document;
var displayEl = doc.getElementById('display');
var exprEl = doc.getElementById('expr');
var buttonsGroup = doc.getElementById('buttons');
var menuOverlay = doc.getElementById('menuOverlay');
var curvePath = doc.getElementById('curve');
var funcInput = doc.getElementById('funcInput');

var scale = 59;
var panX = 0;
var panY = 0;
var originX = 586;
var originY = 204;
var graphW = 590;
var graphH = 460;

function updateDisplay() { displayEl.textContent = currentInput; }

function inputDigit(d) {
if (shouldResetScreen) { currentInput = d; shouldResetScreen = false; }
else { currentInput = currentInput === '0' ? d : currentInput + d; }
updateDisplay();
}

function inputDecimal() {
if (shouldResetScreen) { currentInput = '0.'; shouldResetScreen = false; updateDisplay(); return; }
if (!currentInput.includes('.')) currentInput += '.';
updateDisplay();
}

function handleOperator(op) {
var current = parseFloat(currentInput);
if (operator && !shouldResetScreen) calculate();
previousInput = currentInput;
operator = op;
shouldResetScreen = true;
exprEl.textContent = previousInput + " " + op;
}

function calculate() {
var prev = parseFloat(previousInput);
var curr = parseFloat(currentInput);
if (isNaN(prev) || isNaN(curr)) return;
var result = 0;
switch (operator) {
case '+': result = prev + curr; break;
case '-': result = prev - curr; break;
case '*': result = prev * curr; break;
case '/': result = curr === 0 ? 'Erreur' : prev / curr; break;
case 'pow': result = Math.pow(prev, curr); break;
default: return;
}
if(result !== 'Erreur') {
grandTotal += result;
result = parseFloat(result.toPrecision(12));
}
exprEl.textContent = previousInput + " " + operator + " " + currentInput + " =";
currentInput = String(result);
operator = null;
shouldResetScreen = true;
updateDisplay();
}

function clearAll() { currentInput = '0'; previousInput = ''; operator = null; shouldResetScreen = false; exprEl.textContent = '0'; updateDisplay(); }
function clearEntry() { currentInput = '0'; updateDisplay(); }
function toggleSign() { currentInput = String(parseFloat(currentInput) * -1); updateDisplay(); }
function percentage() { currentInput = String(parseFloat(currentInput) / 100); updateDisplay(); }

function sciFunc(fn) {
var curr = parseFloat(currentInput); var result = 0;
switch(fn) {
case 'sin': result = Math.sin(curr); break;
case 'cos': result = Math.cos(curr); break;
case 'tan': result = Math.tan(curr); break;
case 'asin': result = Math.asin(curr); break;
case 'acos': result = Math.acos(curr); break;
case 'atan': result = Math.atan(curr); break;
case 'log': result = Math.log10(curr); break;
case 'ln': result = Math.log(curr); break;
case 'sqrt': result = Math.sqrt(curr); break;
case 'x^2': result = Math.pow(curr, 2); break;
case '10^x': result = Math.pow(10, curr); break;
case 'e^x': result = Math.exp(curr); break;
case '1/x': result = curr === 0 ? 'Erreur' : 1 / curr; break;
case 'pi': result = Math.PI; break;
case 'e': result = Math.E; break;
}
exprEl.textContent = fn + "(" + currentInput + ")";
currentInput = String(parseFloat(result.toPrecision(12)));
shouldResetScreen = true; updateDisplay();
}

function addData() { dataSet.push(parseFloat(currentInput)); exprEl.textContent = "Data: " + dataSet.length + " valeurs"; shouldResetScreen = true; updateDisplay(); }
function clearData() { dataSet = []; exprEl.textContent = "Data effacée"; currentInput = '0'; updateDisplay(); }

function calcStat(fn) {
if(dataSet.length === 0) { exprEl.textContent = "Erreur: Aucune donnée"; return; }
var n = dataSet.length;
var sum = dataSet.reduce(function(a, b){ return a + b; }, 0);
var mean = sum / n; var result = 0;
switch(fn) {
case 'n': result = n; break;
case 'mean': result = mean; break;
case 'sum': result = sum; break;
case 'med':
var sorted = dataSet.slice().sort(function(a, b){ return a - b; });
var mid = Math.floor(n / 2);
result = n % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
break;
case 'var': result = dataSet.reduce(function(acc, val){ return acc + Math.pow(val - mean, 2); }, 0) / n; break;
case 'std': var v = dataSet.reduce(function(acc, val){ return acc + Math.pow(val - mean, 2); }, 0) / n; result = Math.sqrt(v); break;
}
exprEl.textContent = fn + "(Data)";
currentInput = String(parseFloat(result.toPrecision(12)));
shouldResetScreen = true; updateDisplay();
}

function memOp(op) {
var curr = parseFloat(currentInput);
if(op === 'M+') { memory += curr; exprEl.textContent = "M+ " + curr; }
if(op === 'M-') { memory -= curr; exprEl.textContent = "M- " + curr; }
if(op === 'MRC') { currentInput = String(memory); exprEl.textContent = "Rappel Mémoire"; updateDisplay(); shouldResetScreen = true; return; }
shouldResetScreen = true; updateDisplay();
}

function taxOp(op) {
var curr = parseFloat(currentInput); var taxRate = 0.2; var result = 0;
if(op === 'Tax+') { result = curr * (1 + taxRate); exprEl.textContent = "HT->TTC"; }
else if(op === 'Tax-') { result = curr / (1 + taxRate); exprEl.textContent = "TTC->HT"; }
currentInput = String(parseFloat(result.toPrecision(12)));
shouldResetScreen = true; updateDisplay();
}

function getGT() { currentInput = String(parseFloat(grandTotal.toPrecision(12))); exprEl.textContent = "Grand Total"; shouldResetScreen = true; updateDisplay(); }

function press(key) {
if (key === '00' || key === '000') {
if(currentInput !== '0') { currentInput += key; updateDisplay(); } return;
}
if (!isNaN(key)) { inputDigit(key); return; }
switch(key) {
case '.': inputDecimal(); break;
case '+': case '-': case '*': case '/': case 'pow': handleOperator(key); break;
case '=': calculate(); break;
case 'C': clearAll(); break;
case 'CE': clearEntry(); break;
case '+/-': toggleSign(); break;
case '%': percentage(); break;
case 'sin': case 'cos': case 'tan':
case 'asin': case 'acos': case 'atan':
case 'log': case 'ln': case 'sqrt': case 'x^2':
case '10^x': case 'e^x': case '1/x': case 'pi': case 'e':
sciFunc(key); break;
case 'data+': addData(); break;
case 'Cdata': clearData(); break;
case 'n': case 'mean': case 'sum': case 'med': case 'var': case 'std': calcStat(key); break;
case 'M+': case 'M-': case 'MRC': memOp(key); break;
case 'Tax+': case 'Tax-': taxOp(key); break;
case 'GT': getGT(); break;
}
}

function setMode(mode) {
buttonsGroup.removeAttribute('class');
buttonsGroup.setAttribute('class', 'show-' + mode);
toggleMenu();
clearAll();
}

function setTheme(theme) {
doc.querySelector('svg').removeAttribute('class');
doc.querySelector('svg').setAttribute('class', 'theme-' + theme);
drawGraph();
}

function toggleMenu() { menuOverlay.classList.toggle('visible'); }

function drawGraph() {
var funcStr = funcInput.value;
var pathD = "";
var first = true;
var evalStr = funcStr.replace(/\^/g, '**');

try {
var f = new Function('x', 'return ' + evalStr);
for(var px = 0; px < graphW; px++) {
    var x = (px - (originX - 350 - panX)) / scale;
    var y;
    try { y = f(x); } catch(e) { y = NaN; }

    if(isNaN(y) || !isFinite(y)) { first = true; continue; }
    var py = (originY - panY) - (y * scale);

    if(py < -1000 || py > 1500) { first = true; continue; }

        if(first) { pathD += "M " + (px + 350) + " " + py; first = false; }
        else { pathD += " L " + (px + 350) + " " + py; }
        }
        } catch(e) { pathD = ""; }
        curvePath.setAttribute('d', pathD);
        }

        function zoomGraph(factor) { scale *= factor; drawGraph(); }

        function panGraph(dx, dy) { panX += dx; panY += dy; drawGraph(); }

        function resetZoom() { scale = 59; panX = 0; panY = 0; drawGraph(); }

        drawGraph();
